import 'package:http/http.dart' as http;
import 'dart:convert';

class ApiService {
  final String cloudApiUrl = "https://api.example.com";
  final String localIoTDeviceUrl = "http://192.168.x.x";

  Future<Map<String, dynamic>> fetchCloudData() async {
    try {
      final response = await http.get(Uri.parse(cloudApiUrl));
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      } else {
        throw Exception('Failed to load data from cloud API');
      }
    } catch (e) {
      print("Error fetching cloud data: $e");
      rethrow;
    }
  }

  Future<Map<String, dynamic>> fetchIoTData() async {
    try {
      final response = await http.get(Uri.parse(localIoTDeviceUrl));
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      } else {
        throw Exception('Failed to load data from IoT device');
      }
    } catch (e) {
      print("Error fetching IoT data: $e");
      rethrow;
    }
  }

  Future<void> sendDataToCloud(Map<String, dynamic> data) async {
    try {
      final response = await http.post(
        Uri.parse(cloudApiUrl),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode(data),
      );
      if (response.statusCode == 200) {
        print('Data sent to cloud successfully');
      } else {
        throw Exception('Failed to send data to cloud');
      }
    } catch (e) {
      print("Error sending data to cloud: $e");
      rethrow;
    }
  }

  Future<void> sendDataToIoTDevice(Map<String, dynamic> data) async {
    try {
      final response = await http.post(
        Uri.parse(localIoTDeviceUrl),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode(data),
      );
      if (response.statusCode == 200) {
        print('Data sent to IoT device successfully');
      } else {
        throw Exception('Failed to send data to IoT device');
      }
    } catch (e) {
      print("Error sending data to IoT device: $e");
